const playlist = [
  { id: 1, title: 'Song A', duration: 180, played: true },
  { id: 2, title: 'Song B', duration: 240, played: false },
  { id: 3, title: 'Song C', duration: 150, played: true }
];

// 1. Is every song played?
const allPlayed = playlist.every(s => s.played);

// 2. Is there any long song (> 200s)?
const hasLongSong = playlist.some(s => s.duration > 200);

// 3. Find the first unplayed song
const nextUp = playlist.find(s => !s.played) ?? 'No unplayed songs';

console.log({ allPlayed, hasLongSong, nextUp });

codeExample2.code:
const inventory = [
  { id: 'p1', name: 'Laptop', price: 1000, stock: 5, tags: ['tech', 'work'] },
  { id: 'p2', name: 'Mouse', price: 25, stock: 50, tags: ['tech', 'accessory'] },
  { id: 'p3', name: 'Monitor', price: 300, stock: 0, tags: ['tech', 'display'] }
];

// 1. Get total value of in-stock items
const totalValue = inventory
  .filter(p => p.stock > 0)
  .reduce((sum, p) => sum + (p.price * p.stock), 0);

// 2. Apply 10% discount to all items and mark 'out-of-stock' status
const updatedInventory = inventory.map(p => ({
  ...p,
  price: p.price * 0.9,
  isAvailable: p.stock > 0
}));

// 3. Flatten all tags into one unique array for a 'Filter by Tag' UI
const allTags = [...new Set(inventory.flatMap(p => p.tags))];

console.log('Total Stock Value:', totalValue);
console.log('Unique Tags:', allTags);
console.table(updatedInventory);
